var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"……가끔씩, 그런 생각을 해.","ENG":"(ENG)……가끔씩, 그런 생각을 해."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"ENG":"(ENG)의미없는 후회라는 건 알아."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"만약 처음부터 이렇게 될 줄 알았다면……","ENG":"(ENG)만약 처음부터 이렇게 될 줄 알았다면……"},"stage":{"bg":"MAINSTREAM_NEW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"우린 지금과는 달라졌을까?","ENG":"(ENG)우린 지금과는 달라졌을까?"},"stage":{"bg":"MAINSTREAM_NEW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"ENG":"(ENG)그러니까…… 너는 나처럼 바보 같은 선택을 하지 않길 바래."},"stage":{"bg":"MAINSTREAM_NEW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"의미없는 후회라는 건 알아."},"stage":{"bg":"MAINSTREAM_NEW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"인간도, 신도 지나가 버린 운명을 되돌릴 수는 없으니까.","ENG":"(ENG)인간도, 신도 지나가 버린 운명을 되돌릴 수는 없으니까."},"stage":{"bg":"MAINSTREAM_NEW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니까…… 너는 나처럼 바보 같은 선택을 하지 않길 바래.","ENG":"(ENG)그러니까…… 너는 나처럼 바보 같은 선택을 하지 않길 바래."},"stage":{"bg":"MAINSTREAM_NEW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"가끔은, 포기하는 편이 더 나을 때도 있으니까.","ENG":"(ENG)가끔은, 포기하는 편이 더 나을 때도 있으니까."},"stage":{"bg":"MAINSTREAM_NEW_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니까…… 안녕.","ENG":"(ENG)그러니까…… 안녕."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"이제 헤어질 시간이야.","ENG":"(ENG)이제 헤어질 시간이야."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"네, 부사장님. 지금 막 공항 라운지에 도착했습니다.","ENG":"(ENG)네, 부사장님. 지금 막 공항 라운지에 도착했습니다."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L32_1","type":"subtitle","speaker":null,"text":{"ENG":"(JPN)네. 주무시고 계시네요. 비행기를 오래 타서 피곤하신가 봐요.","TWN":"……告别致辞说完了吗？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"네. 주무시고 계시네요. 비행기를 오래 타서 피곤하신가 봐요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"subtitle","speaker":null,"text":{"ENG":"(JPN)아, 잠시만요. 지금 깨어나신 것 같아요.","TWN":"……告别致辞说完了吗？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"아, 잠시만요. 지금 깨어나신 것 같아요."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"다시 연락드리겠습니다, 부사장님."},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"안녕하세요. 코핀 컴퍼니의 김하나 관리부장이라고 합니다."},"stage":{"bg":"MAINSTREAM_NEW_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_05"},{"id":"L42_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"죄송합니다. 주무시고 계시는데 통화 소리가 너무 컸죠?"},"stage":{"bg":"MAINSTREAM_NEW_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"실은 오늘 저희 회사에 취임하실 새로운 사장님을 모시고 오라는 지시를 받았습니다만,"},"stage":{"bg":"MAINSTREAM_NEW_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"인상착의를 봐선 제가 찾는 분이 맞으시는 것 같은데……?"},"stage":{"bg":"MAINSTREAM_NEW_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"그런 것 같군.","ENG":"(ENG)그런 것 같군."},"stage":{"bg":"MAINSTREAM_NEW_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아, 역시! 늦지 않게 와서 다행이네요!","ENG":"(ENG)아, 역시! 늦지 않게 와서 다행이네요!"},"stage":{"bg":"MAINSTREAM_NEW_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"갑자기 회사를 인수하셔서 어떤 분일까 궁금했는데, 부사장님 말씀보다 더 젊고 훤칠하시네요. ","ENG":"(ENG)갑자기 회사를 인수하셔서 어떤 분일까 궁금했는데, 부사장님 말씀보다 더 젊고 훤칠하시네요. "},"stage":{"bg":"MAINSTREAM_NEW_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":null,"text":{"KOREA":"고……. 고맙군.","ENG":"(ENG)고……. 고맙군."},"stage":{"bg":"MAINSTREAM_NEW_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아, 아니, 무슨 불순한 목적이 있어서 한 말은 아니고요…….","ENG":"(ENG)아, 아니, 무슨 불순한 목적이 있어서 한 말은 아니고요……."},"stage":{"bg":"MAINSTREAM_NEW_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"새로 모시게 된 사장님과 친해지면 좋겠다는…… 그런 공적인 이유 때문입니다.","ENG":"(ENG)새로 모시게 된 사장님과 친해지면 좋겠다는…… 그런 공적인 이유 때문입니다."},"stage":{"bg":"MAINSTREAM_NEW_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"……여, 여기 라운지는 조금 덥네요! 사장님께선 괜찮으세요?","ENG":"(ENG)……여, 여기 라운지는 조금 덥네요! 사장님께선 괜찮으세요?"},"stage":{"bg":"MAINSTREAM_NEW_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"당황하지 않아도 괜찮아.","ENG":"(ENG)당황하지 않아도 괜찮아."},"stage":{"bg":"MAINSTREAM_NEW_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","ENG":"(ENG)……."},"stage":{"bg":"MAINSTREAM_NEW_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아, 어… 어쨌든 바로 회사로 모시겠습니다! 사장님!","ENG":"(ENG)아, 어… 어쨌든 바로 회사로 모시겠습니다! 사장님!"},"stage":{"bg":"MAINSTREAM_NEW_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"슬슬 해가 질 시간이네요.","ENG":"(ENG)슬슬 해가 질 시간이네요."},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아, 혹시 그라운드 원은 처음이세요? 경치가 좀 특이하죠?","ENG":"(ENG)아, 혹시 그라운드 원은 처음이세요? 경치가 좀 특이하죠?"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"저기 보이는 빛이 관리실패 때 생긴 대균열인데, 아직 닫히지 않아서 침식재난이 자주 발생하는 편이에요.","ENG":"(ENG)저기 보이는 빛이 관리실패 때 생긴 대균열인데, 아직 닫히지 않아서 침식재난이 자주 발생하는 편이에요."},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그래도 안심하세요. 그만큼 침식재난에 대응할 태스크포스 컴퍼니들도 많이 모여 있으니까요.","ENG":"(ENG)그래도 안심하세요. 그만큼 침식재난에 대응할 태스크포스 컴퍼니들도 많이 모여 있으니까요."},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"저희 코핀 컴퍼니도 그 중 하나고요.","ENG":"(ENG)저희 코핀 컴퍼니도 그 중 하나고요."},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"그보다, 평소에도 직접 운전하나?","ENG":"(ENG)그보다, 평소에도 직접 운전하나?"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그게…….","ENG":"(ENG)그게……."},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"사장님께서도 잘 아시겠지만, 최근 여러 문제로 회사 재정 상태가 많이 어려웠거든요.","ENG":"(ENG)사장님께서도 잘 아시겠지만, 최근 여러 문제로 회사 재정 상태가 많이 어려웠거든요."},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"저희 태스크포스는 침식체를 쓰러뜨려서 얻은 이터니움으로 수익을 올려야 하잖아요?","ENG":"(ENG)저희 태스크포스는 침식체를 쓰러뜨려서 얻은 이터니움으로 수익을 올려야 하잖아요?"},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"작전에 필요한 인력과 장비에 유지비가 많이 드는데, 사정이 있어서 제대로 된 작전은 못 한 지 한참 됐거든요.","ENG":"(ENG)작전에 필요한 인력과 장비에 유지비가 많이 드는데, 사정이 있어서 제대로 된 작전은 못 한 지 한참 됐거든요."},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"사장님께서 인수해 주시지 않았다면 저희도 지금쯤 파산 절차를 밟고 있었겠죠.","ENG":"(ENG)사장님께서 인수해 주시지 않았다면 저희도 지금쯤 파산 절차를 밟고 있었겠죠."},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그런 상황에 교통비 지원은 사치니까요. 휴우…….","ENG":"(ENG)그런 상황에 교통비 지원은 사치니까요. 휴우……."},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아무튼 그런 이유로, 현재 활동 중인 현장 대원은 한 명뿐입니다.","ENG":"(ENG)아무튼 그런 이유로, 현재 활동 중인 현장 대원은 한 명뿐입니다."},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"그래도 너무 걱정 마세요. 무급 휴직 중이던 소대장님이 이번에 복직하셨거든요.","ENG":"(ENG)그래도 너무 걱정 마세요. 무급 휴직 중이던 소대장님이 이번에 복직하셨거든요."},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"거기에 사장님께서 투자해 주신 자금으로 신입 사원 한 분도 충원했답니다.","ENG":"(ENG)거기에 사장님께서 투자해 주신 자금으로 신입 사원 한 분도 충원했답니다."},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"경력은 짧지만 다른 분들이 베테랑이니까, 빠르게 적응하실 거라고 생각해요.","ENG":"(ENG)경력은 짧지만 다른 분들이 베테랑이니까, 빠르게 적응하실 거라고 생각해요."},"stage":{"bg":"ETERNIUM","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"어라? 도로가 조금 막히네요?","ENG":"(ENG)어라? 도로가 조금 막히네요?"},"stage":{"bg":"GROUND_ONE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그라운드 원, 도시관리국에서 알려드립니다.</color>","ENG":"(ENG)<color=#ffd34c>그라운드 원, 도시관리국에서 알려드립니다.</color>"},"stage":{"bg":"MAINSTREAM_NEW_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재, 도심 전역에 침식파 밀도가 서서히 증가하고 있습니다.</color>","ENG":"(ENG)<color=#ffd34c>현재, 도심 전역에 침식파 밀도가 서서히 증가하고 있습니다.</color>"},"stage":{"bg":"MAINSTREAM_NEW_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>현재의 추세로 볼 때, 곧 카운터사이드 이펙트 경보가 발령될 예정입니다.</color>","ENG":"(ENG)<color=#ffd34c>현재의 추세로 볼 때, 곧 카운터사이드 이펙트 경보가 발령될 예정입니다.</color>"},"stage":{"bg":"MAINSTREAM_NEW_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>민간인은 현장을 통제하는 태스크포스의 지시에 따라 즉각 대피하시기 바랍니다.</color>","ENG":"(ENG)<color=#ffd34c>민간인은 현장을 통제하는 태스크포스의 지시에 따라 즉각 대피하시기 바랍니다.</color>"},"stage":{"bg":"MAINSTREAM_NEW_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"어머, 큰일이네. 하필 이럴 때…….","ENG":"(ENG)어머, 큰일이네. 하필 이럴 때……."},"stage":{"bg":"MAINSTREAM_NEW_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"죄송합니다, 사장님. 아무래도 도착이 늦어질 것 같네요.","ENG":"(ENG)죄송합니다, 사장님. 아무래도 도착이 늦어질 것 같네요."},"stage":{"bg":"MAINSTREAM_NEW_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"부사장님께 연락을 드리려고 하는데, 혹시 지시하실 사항이나 전언이 있으신가요?","ENG":"(ENG)부사장님께 연락을 드리려고 하는데, 혹시 지시하실 사항이나 전언이 있으신가요?"},"stage":{"bg":"MAINSTREAM_NEW_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"요인을 구출해 달라고 전해 주게.","ENG":"(ENG)요인을 구출해 달라고 전해 주게."},"stage":{"bg":"MAINSTREAM_NEW_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"요인 구출……이요?","ENG":"(ENG)요인 구출……이요?"},"stage":{"bg":"MAINSTREAM_NEW_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"알겠습니다. 요인의 인상착의와 위치는 어떻게 전달할까요?","ENG":"(ENG)알겠습니다. 요인의 인상착의와 위치는 어떻게 전달할까요?"},"stage":{"bg":"MAINSTREAM_NEW_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"인상착의는……","ENG":"(ENG)인상착의는……"},"stage":{"bg":"MAINSTREAM_NEW_03","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};